function logTime(ts){if(!ts)return'--:--:--';return new Date(Number(ts)*1000).toLocaleTimeString('en-GB',{hour12:false})}
function logAccountName(e){const p=e?.payload||{};return String(e?.account||p.account||p.account_id||p.display||'System')}
