function renderLogSummary(){const c=logSummaryCounts();[['running',c.running],['verify',c.verify],['recovery',c.recovery],['failed',c.failed]].forEach(([k,v])=>{const el=$('log-sum-'+k);if(el)el.textContent=v})}
function logRawText(e){const p=e?.payload||{};return lower([e?.event_type,e?.reason,p.msg,p.reason,p.step,p.status,p.event_type,p.public_state,p.runtime_state].filter(Boolean).join(' '))}
