function renderLogInspector(items){const box=$('logs-inspector');if(!box)return;let selected=items.find(n=>n.id===LOG_SELECTED_ID)||items[items.length-1];if(!selected){box.innerHTML='<div class="log-inspector-empty">Select an event to inspect metadata.</div>';return}LOG_SELECTED_ID=selected.id;const e=selected.event,meta={event_type:e.event_type||'',reason:e.reason||'',account:selected.account,pid:e.pid||'',runtime_state:e.runtime_state||'',public_state:e.public_state||'',runtime_generation:e.runtime_generation||0,recovery_generation:e.recovery_generation||0,command_generation:e.command_generation||0,session_id:e.session_id||'',transaction_id:e.rejoin_transaction_id||'',severity:e.severity||'',payload:e.payload||{}};box.innerHTML=`<div class="log-inspector-title">${esc(selected.label)} metadata</div><div class="log-meta-grid"><div class="log-meta-item"><span>Account</span><strong>${esc(meta.account||'System')}</strong></div><div class="log-meta-item"><span>PID</span><strong>${esc(meta.pid||'-')}</strong></div><div class="log-meta-item"><span>Runtime</span><strong>${esc(meta.runtime_state||'-')}</strong></div><div class="log-meta-item"><span>Public</span><strong>${esc(meta.public_state||'-')}</strong></div></div><pre class="log-json">${esc(JSON.stringify(meta,null,2))}</pre>`}
function renderLogs(){renderLogSummary();document.querySelectorAll('[data-log-filter]').forEach(b=>b.classList.toggle('active',b.dataset.logFilter===LOG_FILTER));const rawMode=LOG_FILTER==='raw',obs=$('log-observability'),raw=$('logs-raw'),timeline=$('logs-timeline');if(obs)obs.hidden=rawMode;if(raw)raw.hidden=!rawMode;if(rawMode){$('logbox').innerHTML=(LOGS.length?LOGS:['No raw log lines yet.']).map(line=>`<div class="log-line">${esc(line)}</div>`).join('');return}if(!timeline)return;const items=RUNTIME_EVENTS.slice().sort((a,b)=>(Number(a.ts||0)-Number(b.ts||0))).map(normalizeLogEvent).filter(logVisible).slice(-220);if(!items.length){timeline.innerHTML='<div class="log-inspector-empty" style="padding:14px">No important runtime events yet.</div>';renderLogInspector([]);return}const groups=[];items.forEach(n=>{const key=n.account+'|'+(n.tx||'runtime');let g=groups.find(x=>x.key===key);if(!g){const account=ACCOUNTS.find(a=>lower(a.username)===lower(n.account)||lower(a.display)===lower(n.account));g={key,account:n.account,state:account?rowStatusLabel(account,bucket(account)):(n.event.public_state||n.event.runtime_state||''),items:[]};groups.push(g)}g.items.push(n)});timeline.innerHTML=groups.map(g=>`<section class="log-group"><div class="log-group-head"><div class="log-group-name">${esc(g.account||'System')}</div><div class="log-group-state">${esc(g.state||'Runtime')}</div></div>${g.items.map(n=>`<div class="log-event event-${n.kind} ${n.id===LOG_SELECTED_ID?'selected':''}" data-event-id="${esc(n.id)}"><div class="log-time">${esc(logTime(n.ts))}</div><div class="log-icon">${esc(n.icon)}</div><div><div class="log-event-title">[${esc(n.label)}] ${esc(n.title)}</div><div class="log-event-sub">${esc(n.sub||'metadata hidden')}</div></div></div>`).join('')}</section>`).join('');renderLogInspector(items)}
