function openAdd(){openCookie()}
function openCookie(){modal('Import Cookies',`<div class="field"><div class="hint">One cookie per line.</div><textarea id="cookie-lines" class="textarea" placeholder="user1:pass1:_|WARNING:...&#10;_|WARNING:cookie-only..."></textarea></div>`,`<button class="btn ghost" id="cookie-cancel">Cancel</button><button class="btn good" id="cookie-add">Add Accounts</button>`);$('cookie-cancel').onclick=closeModal;$('cookie-add').onclick=submitCookies}
function parseCookieLine(line){const idx=line.indexOf('_|WARNING:');if(idx>=0)return{username:(line.slice(0,idx).split(':')[0]||'').trim(),cookie:line.slice(idx).trim()};const parts=line.split(':');if(parts.length>=3)return{username:parts[0].trim(),cookie:parts.slice(2).join(':').trim()};return{username:'',cookie:line.trim()}}
