async function saveGraphics(){const enabled=$('graphics-auto-enabled').checked;const body={graphics_low_enabled:enabled,graphics_auto_enabled:enabled,graphics_quality_level:Number($('graphics-quality').value)||1,auto_process_priority_enabled:$('priority-enabled').checked,process_priority:$('process-priority').value};try{GRAPHICS=await api('/performance/graphics','POST',body);clearDirty('graphics');renderGraphics();toast(GRAPHICS.warning||'Graphics saved');if(GRAPHICS.warning)$('graphics-notice').textContent=GRAPHICS.warning;await loadConfig()}catch(e){$('graphics-notice').textContent=e.message;$('graphics-notice').classList.add('show');toast(e.message)}}
async function saveWindowSize(){const preset=$('window-size-preset').value;const body={enabled:$('window-size-enabled').checked,preset:preset,width:Number($('window-size-width').value)||640,height:Number($('window-size-height').value)||480,arrange_enabled:$('window-arrange-enabled').checked,arrange_columns:Number($('window-arrange-columns').value)||6,arrange_gap:Number($('window-arrange-gap').value)||2};try{WINDOW_SIZE=await api('/performance/window-size','POST',body);clearDirty('window-size');await loadConfig();renderWindowSize();toast(WINDOW_SIZE.msg||'Window size saved')}catch(e){$('window-size-notice').textContent=e.message;$('window-size-notice').classList.add('show');toast(e.message)}}
function collectCpuRows(){if($('cpu-apply-all').checked)return[];return Array.from(document.querySelectorAll('#cpu-account-rows tr')).map(row=>{const enabled=row.querySelector('.cpu-row-enabled'),limit=row.querySelector('.cpu-row-limit'),user=enabled?.dataset.user||limit?.dataset.user||'';return user?{username:user,enabled:!!enabled?.checked,limit_percent:Number(limit?.value)||20}:null}).filter(Boolean)}
async function saveCpuLimiter(){const body={enabled:$('cpu-enabled').checked,mode:$('cpu-mode').value,default_limit_percent:Number($('cpu-default-limit').value)||20,apply_all:$('cpu-apply-all').checked,accounts:collectCpuRows()};try{CPU_LIMITER=await api('/performance/cpu-limiter','POST',body);clearDirty('cpu-limiter');renderCpuLimiter();toast('CPU limiter saved')}catch(e){$('cpu-notice').textContent=e.message;$('cpu-notice').classList.add('show');toast(e.message)}}
function connectStream(){if(!window.EventSource){setStreamState('polling');setInterval(manualSnapshot,1500);manualSnapshot();return}const es=new EventSource('/api/stream');setStreamState('connecting');es.addEventListener('snapshot',async ev=>{const nextStatus=JSON.parse(ev.data);if(!acceptStatus(nextStatus,0))return;setStreamState('live','stream online');await loadAccountsConfig();render();loadAvatars().catch(()=>{})});es.onerror=()=>setStreamState('reconnecting');manualSnapshot();setInterval(manualSnapshot,2500)}
document.querySelectorAll('#nav button').forEach(b=>b.onclick=()=>setView(b.dataset.view));
document.addEventListener('change',e=>{if(e.target?.matches?.('.toggle-row input[type="checkbox"]'))syncToggleLabels()});
$('guard-btn').onclick=toggleGuard;$('add-btn').onclick=openAdd;$('reload-cookies-btn').onclick=reloadCookies;$('close-all-roblox-btn').onclick=closeAllRoblox;$('modal-close').onclick=closeModal;$('account-search').oninput=renderAccountsTable;$('game-reset').onclick=resetGameSettings;$('game-save').onclick=saveGame;$('game-lookup').onclick=lookupGame;$('fps-reset').onclick=resetPerformanceSettings;$('fps-save').onclick=savePerformance;$('graphics-reset').onclick=resetGraphicsSettings;$('graphics-save').onclick=saveGraphics;$('window-size-reset').onclick=resetWindowSizeSettings;$('window-size-save').onclick=saveWindowSize;$('cpu-reset').onclick=resetCpuLimiterSettings;$('cpu-save').onclick=saveCpuLimiter;$('queue-reset').onclick=resetQueueSettings;$('queue-save').onclick=saveQueue;$('roblox-uninstall').onclick=()=>robloxInstallConfirm('uninstall');$('roblox-latest').onclick=()=>robloxInstallConfirm('latest');
$('game-auto-private-enabled').onchange=()=>{markDirty('game');renderSettings()};$('game-multi-roblox').onchange=()=>{markDirty('game');renderSettings()};$('fps-enabled').onchange=()=>{markDirty('performance');renderPerformance()};$('fps-limit').oninput=()=>markDirty('performance');$('priority-enabled').onchange=()=>{markDirty('graphics');renderGraphics()};$('graphics-auto-enabled').onchange=()=>{markDirty('graphics');renderGraphics()};$('graphics-quality').oninput=()=>markDirty('graphics');$('process-priority').onchange=()=>markDirty('graphics');$('window-size-enabled').onchange=()=>{markDirty('window-size');renderWindowSize()};$('window-size-preset').onchange=()=>{markDirty('window-size');renderWindowSize()};$('window-size-width').oninput=()=>markDirty('window-size');$('window-size-height').oninput=()=>markDirty('window-size');$('window-arrange-enabled').onchange=()=>{markDirty('window-size');renderWindowSize()};$('window-arrange-columns').oninput=()=>markDirty('window-size');$('window-arrange-gap').oninput=()=>markDirty('window-size');$('cpu-enabled').onchange=()=>{markDirty('cpu-limiter');renderCpuLimiter()};$('cpu-mode').onchange=()=>markDirty('cpu-limiter');$('cpu-default-limit').oninput=()=>{markDirty('cpu-limiter');renderCpuLimiter()};$('cpu-apply-all').onchange=()=>{markDirty('cpu-limiter');renderCpuLimiter()};$('cpu-account-rows').addEventListener('input',()=>markDirty('cpu-limiter'));$('cpu-account-rows').addEventListener('change',()=>markDirty('cpu-limiter'));$('queue-autoclose-enabled').onchange=()=>{markDirty('queue');renderSettings()};$('queue-autoclose-minutes').oninput=()=>markDirty('queue');$('popup-disconnected-enabled').onchange=()=>{markDirty('queue');renderSettings()};$('popup-scan-interval').oninput=()=>markDirty('queue');$('popup-scan-max-parallel').oninput=()=>markDirty('queue');$('presence-enabled').onchange=()=>markDirty('queue');$('queue-max').oninput=()=>markDirty('queue');$('queue-duration').oninput=()=>markDirty('queue');$('queue-delay').oninput=()=>markDirty('queue');
$('game-place').addEventListener('input',()=>{markDirty('game');clearTimeout(gameLookupTimer);const place=$('game-place').value.trim();renderGameMap(place);if(/^\d{3,}$/.test(place))gameLookupTimer=setTimeout(()=>loadGamePlace(place,true).catch(e=>renderGameMap(place,null,e.message)),650)});
$('game-private').addEventListener('input',()=>markDirty('game'));
$('game-private').addEventListener('blur',()=>{if($('game-place').value.trim())return;const place=placeFromPrivate($('game-private').value.trim());if(place){$('game-place').value=place;markDirty('game');loadGamePlace(place,true).catch(e=>renderGameMap(place,null,e.message))}});
$('accounts-table').addEventListener('click',e=>{const btn=e.target.closest('[data-action]');if(btn){e.stopPropagation();if(btn.dataset.action==='delete')deleteAccount(btn.dataset.user);if(btn.dataset.action==='launch')launchAccount(btn.dataset.user);if(btn.dataset.action==='dedupe')dedupeAccount(btn.dataset.user);return}const row=e.target.closest('tr[data-user]');if(row){selectedUser=row.dataset.user;localStorage.setItem('rg_selected',selectedUser);renderAccountsTable()}});
$('accounts-table').addEventListener('keydown',e=>{if(e.target.classList.contains('desc-input')&&e.key==='Enter'){e.preventDefault();e.target.blur()}});
$('accounts-table').addEventListener('focusout',e=>{if(e.target.classList.contains('desc-input'))saveDescription(e.target.dataset.user,e.target.value).catch(err=>toast(err.message))});
(async function init(){setView(VIEW);await loadConfig();await loadPerformance();await loadGraphics();await loadWindowSize();await loadCpuLimiter();await loadTroubleshoot();await loadAccountsConfig(true);connectStream();setInterval(renderRunningClock,1000);setInterval(()=>{if(VIEW==='troubleshoot')loadTroubleshoot();if(VIEW==='cpu-limiter')loadCpuLimiter()},3500)})();
